VALUES
  ('judicial-57f41407-moex-00363', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '關於各國政府體制所依循的基本原則說明，下列敘述何者正確？', '["總統制國家中的總統，基於依法行政原則之要求，必須向國會負責", "內閣制國家中的最高行政首長為內閣首相，且不會設有總統職位", "共和國是相對於君主國之概念，因此共和國並不必然是民主政體國家", "多數民主國家為落實國民主權，於憲法明文保障人民的創制與複決權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00364', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '世界貿易組織為目前少數我國得以正式參與之國際組織，我國是於2002年以下列何種名義申請加入 該組織？', '["中華民國", "臺灣地區", "中華臺北", "臺澎金馬個別關稅領域"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00365', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '為落實國際人權規範，我國於民國98年制定「人權兩公約施行法」，將人權兩公約正式轉換為具有國 內法效力之具體規範。所謂人權兩公約是指「公民與政治權利國際公約」，以及下列何項國際條約？', '["兒童權利公約", "經濟社會文化權利國際公約", "消除對婦女一切形式歧視公約", "聯合國禁止酷刑公約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00366', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '我國現行中央政府體制，那項與日本的制度相似？', '["總統由人民直接選舉產生，與行政院院長共享行政實權", "依照慣例，由立法院獲得過半席次政黨之黨揆出任行政院院長", "立法院對行政院的施政不滿意時，可向行政院院長提出不信任案", "行政院認為立法院通過的法律案窒礙難行時，可經總統核可，移請立法院覆議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00367', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '我國自蔣經國總統任內解除戒嚴，到李登輝總統宣布終止動員戡亂時期臨時條款，再至一連串修憲， 如總統直接民選、廢除國民大會等憲政改革，使臺灣的民主逐漸站穩腳步。下列幾起重要歷史事件， 關於其背後象徵意涵的敘述何者正確？', '["1987年臺灣宣告解除戒嚴，使得第一屆國大代表與立法委員能夠全面退職", "1991年終止動員戡亂時期臨時條款，為臺灣承認兩岸實際分治的法理前提", "透過修憲將「中華民國主權及於自由地區與中國大陸」列入憲法增修條文中", "前總統李登輝先生提出的特殊國與國關係，就是指「九二共識，一中各表」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00368', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依我國憲法及憲法增修條文之規定，關於我國政府體制的設計，下列那些運作模式不是內閣制的特 色？', '["行政院院長以及各部會首長有義務至立法院接受質詢", "立法委員得經由表決方式對總統及副總統提出彈劾案", "總統公布法律及命令，原則上須經行政院院長之副署", "立法委員可透過連署方式對行政院院長提出不信任案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00369', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '根據我國現行行政救濟制度，下列何者正確？', '["不服行政機關拆除違建並執行完畢的行政處分，向上級機關提起訴願", "學生不服學校對其上課遲到以曠課論處，逕向上級機關提出訴願", "民眾不服員警未依規定攔查便逕行舉發交通違規，遂向上級機關提出訴願", "某校長不服遭法務部以違反利益迴避規定處以罰鍰，遂向行政院提出訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00370', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某甲因違反道路交通處罰條例遭檢方起訴，法官在審理該案時，認為此條例部分條文有違憲疑慮，可 能會影響判決結果。關於該案當事人與法官後續可採取的作為，下列何者符合我國現行相關法律的規 定？', '["該案當事人可對行政機關主張信賴保護原則，提出訴願要求撤銷處分", "該案當事人可要求法官依惡法非法論認定該條例違憲，為無罪之判決", "法官可裁定停止該案訴訟程序，以法院名義聲請司法院憲法法庭裁判以求解決", "該案當事人可逕向司法院大法官提出釋憲聲請以解決此問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00371', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依司法院大法官解釋，關於新聞自由，下列敘述何者正確？', '["僅有依法持有新聞記者資格，並受僱於主要新聞媒體事業者始得主張新聞自由", "新聞自由的保障範圍限於新聞媒體傳播具新聞價值之多元資訊，而不及於相關新聞查證行為", "新聞記者之採訪行為不僅受憲法第11條之保障，同樣涉及憲法第15條所稱工作權之保障", "個人於公共場域之行動即無隱私權之保護可得主張，因此新聞記者於公共場域監看或跟追採訪對 象，亦無違法可能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00372', 'judicial-57f41407', 'judicial-57f41407-moex-112-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '民法第1084條第1項規定，子女應孝敬父母。此種未明定法律效果之規定，學理上稱為下列何種規 定？', '["取締規定", "訓示規定", "強制規定", "任意規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "592174564449", "answer_pdf_sha1": "1a174208cd01", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
